static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    uint32_t inH  = static_cast<uint32_t>(x_shape->GetDim(2));
    uint32_t inW  = static_cast<uint32_t>(x_shape->GetDim(3));
    uint32_t outC = static_cast<uint32_t>(w_shape->GetDim(0));
    uint32_t kH   = static_cast<uint32_t>(w_shape->GetDim(2));
    uint32_t kW   = static_cast<uint32_t>(w_shape->GetDim(3));
    // Assumptions: pad=0, stride=1, dilation=1
    uint32_t outH = (inH + 2*0 - 1*(kH-1) -1)/1 + 1;
    uint32_t outW = (inW + 2*0 - 1*(kW-1) -1)/1 + 1;

    // Get output shape pointer and copy then modify
    gert::Shape *y_shape = context->GetOutputShape(0);
    *y_shape = *x_shape;
    y_shape->SetDim(1, static_cast<int64_t>(outC));
    y_shape->SetDim(2, static_cast<int64_t>(outH));
    y_shape->SetDim(3, static_cast<int64_t>(outW));

    return GRAPH_SUCCESS;
}

